var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"나는 항상 적막한 후회의 길을 걷고 있으니.","JPN":"我は常に寂寞たる後悔の道を歩んでいる。","ENG":"I'm the one always walking on the silent path of regret.","TWN":"我總是走在淒涼的悔恨之路上。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"그 근원을 파헤치면 무수하게 희생된 인명 탓도 아니오. 이웃한 세상에 화가 미친 것이 괴로운 탓도 아니오.","JPN":"その根源は犠牲になった無数の人命のせいでもなく、隣接した世界に起こった災いによる苦痛のせいでもない。","ENG":"The creation of this path, was not due to the countless lives lost, nor the pain felt as a result from calamity to a neighboring world.","TWN":"要說到原因，不是因為那犧牲的無數條人命，也不是因為難過殃及無辜。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"다만 그 자가 왕을 자처하게 한 나의 잘못된 선택 탓이라.","JPN":"ただその者が王を名乗ることを放置した我の誤った選択のせいであろう。","ENG":"It was because of my foolish choice to support her claim as a queen.","TWN":"而是因為我錯誤的決定，讓她自命為王。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"이 깊고 어두운 수렁 속에서 내게 주어진 불씨는 오직 후회뿐이로다.","JPN":"この深く暗い泥沼のなかで我に与えられた火種はただ後悔のみ。","ENG":"In this deep and dark pit, the only flicker of light is that of regret.","TWN":"在這深淵泥沼裡，我得到的就只有悔恨。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"언제나 한 발 늦는구나, 불경하기 짝이 없는 방랑자여.","JPN":"いつも一足遅れて来るのだな、不敬極まる放浪者よ。","ENG":"You're always a step behind, ye filthy Wayfarer.","TWN":"總是晚一步啊，狂妄的流浪者。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"너를 위해 불러들였던 짐승들은 어떠했느냐.","JPN":"貴様のためにおびき寄せた獣は気に入ってくれたか。","ENG":"How did you like the beasts I summoned for you?","TWN":"為你喚來的那些野獸如何啊。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"......그녀를 우롱했군.","JPN":"……彼女を愚弄したな。","ENG":"You've made a mockery of her...","TWN":"……你竟愚弄了她。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"처음부터 그 아이는 인질이었나.","JPN":"最初からあの子は人質だったのか。","ENG":"So the child was nothing but a hostage all along.","TWN":"從一開始那個孩子就是人質吧。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"미물들 사이에 숨어 살면서, 그들에 대해선 여전히 모르는구나.","JPN":"下等な微物に紛れて生きているにもかかわらず、彼らについて相変わらず無知なのだな。","ENG":"You dwell among the mortals, yet you haven't learned a thing about them.","TWN":"你隱匿在這些微不足道的廢物身邊生活，卻對他們還不是很瞭解啊。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"미물들은...... 자신이 소중하다고 여기는 상대의 안위에 충동적으로 반응하지.","JPN":"下等な微物は……自分が大切だと思っている相手の安否に衝動的に反応する。","ENG":"These mortals... always respond on impulse when it comes to the well-being of those they hold dear.","TWN":"微不足道的廢物……會因為自己珍視的對方安危與否而做出衝動的反應。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"그것을 활용하면, 아주 작은 자극만으로도 헛된 반항심을 무너뜨릴 수 있다.","JPN":"それを活用すれば、ほんの少しの刺激で無駄な反抗を抑えることができる。","ENG":"If you leverage that... Even the tiniest prod can sufficiently topple any resistance.","TWN":"好好利用這一點，一些小小的刺激就能讓他們的反抗心徹底崩塌。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"그 여자...... 재조립되면서 정말 아름답게 지저귀더구나.","JPN":"あの女……組み直されながら実に美しく叫んでいた。","ENG":"As for the woman... How beautifully she chirped as she was reassembled.","TWN":"那個女人……重新組裝的時候，叫聲真是美麗。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그들에게 죄가 있다면 타기리온의 눈에 띄었다는 것뿐이다.","JPN":"彼女らに罪があるとすれば、タギリオンの目に留まったということだけだ。","ENG":"Their only crime is that they unwittingly drew Thagirion's attention.","TWN":"如果說他們有罪的話，就是不應該出現在塔基里翁眼前。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"너는 저들이 당한 모욕을...... 장난인 양 떠드는구나.","JPN":"お前は彼女らが受けた侮辱を……イタズラのようなものとほざいておる。","ENG":"And yet you jest... as if their suffering was but child's play.","TWN":"你侮辱欺騙她們……卻洋洋自得。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"말하지 않았느냐, 방랑자. 그분의 계획에 만약이란 존재할 수 없도다.","JPN":"言ったはずだ、放浪者よ。あのお方の計画に万が一は存在しないと。","ENG":"Have I not told you, Wayfarer? The King's plans are inevitable.","TWN":"我不是說了嗎，流浪者。王的計畫沒有萬一。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"한낱 미물들의 목숨으로 왕께서 만족하신다면, 분수에 넘치게 값진 결말일 터.","JPN":"一介の微物の命で王が満足されるなら、身に余るほどの貴重な結末に間違いない。","ENG":"If the queen finds their petty lives pleasing, there is no greater glory for these mere mortals.","TWN":"如果區區一個微不足道的廢物性命能讓我的王滿意，那就是非常有價值的。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그것이...... 왕을 자처하는 자로서 올바른 행동인가?","JPN":"それが……王を名乗る者として正しい行動なのか？","ENG":"Tell me... Is that behavior truly fitting of a self-proclaimed queen?","TWN":"這……是作為以王自居的人的正確行為嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"희생양들의 영혼을 자신의 욕망으로 일그러뜨리고, 꼭두각시로 만드는 것이?","JPN":"犠牲者の魂を自らの欲望で壊して、操り人形にすることが？","ENG":"To soil the souls of the innocent and turn them into puppets?","TWN":"把犧牲品的靈魂扭曲成自己的欲望，變成傀儡？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"......불경한 것. 네가 아직도 훈계 따위를 늘어놓을 위치라고 생각하느냐.","JPN":"……不敬者。貴様がまだ訓戒を垂れる立場だと思うのか。","ENG":"Blasphemous fool. Do you really think you are still in a position to lecture thusly?","TWN":"……倡狂的東西。你以為你有資格訓誡我嗎。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"왕께서 걸음 하실 때, 너는 이번에야말로 덧없이 사라지게 되리라.","JPN":"王が降臨される際、今度こそ貴様は儚く消えるのであろう。","ENG":"When the queen proceeds, you shall finally perish into oblivion, once and for all.","TWN":"當王能夠行動時，也就是你灰飛煙滅的時刻。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"......"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그렇게 되도록 좌시하지 않을 것이다. 솔리키타티오.","JPN":"そうなるまで座視しはせぬぞ。ソリキタティオ。","ENG":"I shall not stand by idly. Sollicitatio.","TWN":"索爾奇塔提奧，我不會坐視不管的。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"가서 타기리온에게 전하라.","JPN":"タギリオンに伝えろ。","ENG":"Tell Thagirion if you must.","TWN":"去告訴塔基里翁！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"설령 허상 같은 자매들을 무수히 가질지라도, 네가 바라는 세상을 만들 수 없을 것이라고.","JPN":"たとえ虚像のような姉妹たちを無数に持つとしても、貴様が望む世界は作れぬ。","ENG":"No matter the number of delusional sisters, she shall not be able to create the world she so desires.","TWN":"就算你擁有再多虛幻的姊妹，也無法打造出你想要的世界的！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"저 하찮은 것이…… 왕의 행보를 능멸하려 들어?","JPN":"愚か者が……王の歩みを侮辱するか！？","ENG":"Petty thing... How dare does one intend to undermine the actions of the queen!","TWN":"你這卑賤的東西……是想藐視王命？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"하아……! 하아……!","JPN":"はあ……！　はあ……！","ENG":"*Huff…!* *Huff…!*","TWN":"呼呼……！呼呼！……！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MINISTRA_CORRUPT_DREAD_NULL","text":{"KOREA":"왜 그러니, 우리 귀여운 동생? 내 몸에 상처를 내고도 만족하지 못하겠니?","JPN":"どうしたんだ、かわいい妹よ？　私の体に傷をつけたのに満足できないのか？","ENG":"What’s wrong, my cute little sister? Wounding me doesn’t satisfy you?","TWN":"怎麼啦，我可愛的妹妹？你在我身上留下這麼多傷還不滿意嗎？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPT_DREAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MINISTRA_CORRUPT_DREAD_NULL","text":{"KOREA":"투정은 그만 부리는 게 좋을 거야. 참고 받아 주는 데에도 한계가 있으니까.","JPN":"だだをこねるのもいい加減にしなさい。我慢するにも限界がある。","ENG":"Please. Cease your whining. I’ve done my best to be understanding but even I have my limits.","TWN":"我勸你別再掙扎，我的忍耐是有限的。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPT_DREAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"언……. 니……. 저, 막아 주지 못해서, 미안…….","JPN":"お姉……ちゃん……私、止められなくて、ごめん……","ENG":"I… I’m sorry... I couldn’t stop you from...","TWN":"姊……姊……對不起，沒能阻止……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MINISTRA_CORRUPT_DREAD_NULL","text":{"KOREA":"후후, 제 풀에 지쳐 쓰러졌구나.","JPN":"ふふ、耐えきれずに倒れたか。","ENG":"Fuu fuu... So exhausted you cannot stand?","TWN":"呵呵，自己累倒啦？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPT_DREAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MINISTRA_CORRUPT_DREAD_NULL","text":{"KOREA":"하지만 안심하렴. 이제 아무것도 무서워하지 않아도 돼.","JPN":"だが安心しろ。もう何も怖がることはない。","ENG":"Worry not. There is no need for you to fear anything any more.","TWN":"放心吧，之後就不需要再害怕。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPT_DREAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MINISTRA_CORRUPT_DREAD_NULL","text":{"KOREA":"더 이상 고민도, 두려움도 느낄 필요 없게……. 재조립해 줄 테니까.","JPN":"もう悩みも、恐怖も感じることのないように……組み直ししてやろう。","ENG":"Worries, fears, you have no need of them... For I will reassemble you.","TWN":"等我幫你重新組裝完後……你就再也不會感到煩惱、憂愁。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPT_DREAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MINISTRA_CORRUPT_DREAD_NULL","text":{"KOREA":"뭐야, 감히 누가……!","JPN":"なんだ、いったい誰が……！","ENG":"What, who dares...!","TWN":"可惡，是誰……！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPT_DREAD_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L1_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"어찌하여 피하는가. 망자의 가죽에 삼켜진 자여.","JPN":"なぜ避けるのだ。亡者の皮に飲み込まれた者よ。","ENG":"You managed to avoid it. One who wears the body of the dead.","TWN":"披著死人外皮的人，你怎麼能避開呢？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L2_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"비록 죄없는 피에 더럽혀진 단두대이나, 너에게 안식을 선사하고자 하노라.","JPN":"罪なき血で汚された断頭台ではあるが、貴様に安息を与えてやろうではないか。","ENG":"Even if my guillotine becomes soiled with the blood of the innocent, you require eternal rest.","TWN":"雖然斷頭台被無辜的血給玷汙，但我要讓你進入安息。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MINISTRA_CORRUPT_DREAD_NULL","text":{"KOREA":"……단두대?","JPN":"……断頭台？","ENG":"...Guillotine?","TWN":"……斷頭台？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPT_DREAD_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MINISTRA_CORRUPT_DREAD_NULL","text":{"KOREA":"그렇군. 네가 입은 그것은 전쟁에 나간 죄인을 구속하는 갑주…….","JPN":"そうか。お前が着ているそれは戦争に出た罪人を拘束する甲冑……","ENG":"Ah, I see now. That armor... The battle armor of that sinner.","TWN":"原來如此，你身上穿的，就是拘禁戰俘的鎧甲……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPT_DREAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MINISTRA_CORRUPT_DREAD_NULL","text":{"KOREA":"<color=#ffd34c>나</color>의 기억에도 남아 있어. 불경한 방랑자.","JPN":"<color=#ffd34c>私</color>の記憶にも残っている。不敬な放浪者。","ENG":"<color=#ffd34c>I</color> remember now. Blasphemous Wayfarer.","TWN":"<color=#ffd34c>我</color>還有印象，狂妄的流浪者。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPT_DREAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MINISTRA_CORRUPT_DREAD_NULL","text":{"KOREA":"아니, 예하라고 불러드려야 하나?","JPN":"いや、猊下と呼ぶべきか？","ENG":"Or, should I be referring to you as Eminence?","TWN":"不，還是我應該稱呼你為主教？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPT_DREAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그 간사한 혀로 얼마든지 조롱해 보아라. 단두대의 칼날은…….","JPN":"その腹黒い口でいくらでも嘲弄しろ。断頭台の刃は……","ENG":"Mock me if you wish with your devious tongue. The blade of the guillotine...","TWN":"你那詭詐的舌頭就儘管嘲諷吧！斷頭台的刀刃……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_NULL","text":{"KOREA":"……멈추지 않을지니, 였던가?","JPN":"……止まらぬ、であったか？","ENG":"...Cannot be stopped? Was that it?","TWN":"……不會停的，是這樣嗎？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NERVIA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"자매들을 불러들였구나. 솔리키타티오.","JPN":"姉妹たちを呼び寄せたのだな。ソリキタティオ。","ENG":"You called for your sisters, Sollicitatio.","TWN":"索爾奇塔提奧，你把姊妹都找來了是嗎？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"그렇다. 갓 눈을 뜬 자매에게 너와 피를 보라는 것은 가혹한 처사이지.","JPN":"そうだ。目を覚ましたばかりの姉妹にお前と血戦を繰り広げろというのは過酷な仕打ちだろう。","ENG":"Indeed, although it would be a bit much to make a newly awoken sister fight you.","TWN":"沒錯，讓才剛睜開眼的姊妹和你廝殺，很殘忍吧？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"내 비록 실체를 비출 수 없을지라도, 나의 자매들마저 그러겠느냐.","JPN":"たとえ我の実体を現わすことができずとも、姉妹がすべからくそうだとは限るまい。","ENG":"Even if I cannot reveal my true form, my sisters are not like me.","TWN":"雖然我的本體無法出現，但你以為我的姊妹們辦不到嗎！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"수가 많다고 한들 타기리온의 미련이 자아낸 허상일 뿐.","JPN":"数は多くあれども、タギリオンの未練が起こした虚像に過ぎない。","ENG":"No matter how many there are, it’s all just an illusion created by Thagirion’s regrets.","TWN":"你們數量再多，也不過是塔基里翁幻想出來的幻影。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"자매들을 호령해 보아라. 솔리키타티오.","JPN":"姉妹たちに号令してみせよ。ソリキタティオ。","ENG":"Bring all of your sisters. Sollicitatio.","TWN":"索爾奇塔提奧，叫你的姊妹一起上吧！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"수백이든 수천이든. 모두 안식에 들게 해 주마.","JPN":"数百でも、数千でも。みな安息へ導いてやろう。","ENG":"Hundreds. Thousands. I shall lay you all to rest.","TWN":"不管你們有數百或數千個，我都會讓你們進入安息！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"……이제까지 그랬듯이.","JPN":"……これまでどおり。","ENG":"...As it has always been to this day.","TWN":"……一如往常。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};